/// Axis direction options for layout widgets.
///
/// Defines the main axis direction for flex layouts like Row and Column.
enum StacAxis {
  /// Horizontal axis (left to right).
  ///
  /// Used by Row widgets where children are arranged horizontally.
  horizontal,

  /// Vertical axis (top to bottom).
  ///
  /// Used by Column widgets where children are arranged vertically.
  vertical,
}
